def _normalize_passport(val):
    """Strip, uppercase, remove spaces."""
    if not val: return ''
    return re.sub(r'\s+', '', val.strip().upper())

def _normalize_cnic(val):
    """Strip dashes, spaces."""
    if not val: return ''
    return re.sub(r'[\s\-]', '', val.strip())

def _generate_charter_ref(db=None):
    """Generate a unique TFR-XXXX reference number."""
    close_after = False
    if db is None:
        db = get_db()
        close_after = True
    try:
        while True:
            num = secrets.randbelow(9000) + 1000
            ref = f'TFR-{num}'
            exists = db.execute("SELECT 1 FROM charter_interest WHERE reference_number = ?", [ref]).fetchone()
            if not exists:
                return ref
    finally:
        if close_after:
            db.close()

def find_or_create_person(db, data):
    """
    Passport-first identity resolution against person_master,
    with fallback to CNIC and Civil ID. Links to existing evacuee
    record if found. Returns person_master.id
    """
    passport = _normalize_passport(data.get('passport'))
    cnic = _normalize_cnic(data.get('cnic'))
    civil_id = (data.get('civil_id') or '').strip()
    mobile = (data.get('mobile') or '').strip()

    person = None

    # Primary match: passport
    if passport:
        person = db.execute(
            "SELECT id FROM person_master WHERE UPPER(REPLACE(passport,' ','')) = ?",
            [passport]).fetchone()

    # Secondary: CNIC
    if not person and cnic:
        person = db.execute(
            "SELECT id FROM person_master WHERE REPLACE(REPLACE(cnic,'-',''),' ','') = ?",
            [cnic]).fetchone()

    # Secondary: Civil ID
    if not person and civil_id:
        person = db.execute(
            "SELECT id FROM person_master WHERE TRIM(civil_id) = ?",
            [civil_id]).fetchone()

    if person:
        return person['id']

    # No match — create new person_master record
    # Also try to link to existing evacuees table
    evacuee_link = None
    if passport:
        ev = db.execute("SELECT id FROM evacuees WHERE UPPER(TRIM(passport)) = ?", [passport]).fetchone()
        if ev:
            evacuee_link = ev['id']
    if not evacuee_link and cnic:
        ev = db.execute("SELECT id FROM evacuees WHERE REPLACE(REPLACE(cnic,'-',''),' ','') = ?", [cnic]).fetchone()
        if ev:
            evacuee_link = ev['id']

    cur = db.execute("""
        INSERT INTO person_master
            (full_name, father_name, gender, date_of_birth, nationality,
             passport, passport_expiry, cnic, civil_id,
             mobile, whatsapp, alt_mobile, email,
             emergency_name, emergency_relation, emergency_phone,
             evacuee_link_id, created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?, CURRENT_TIMESTAMP)
    """, [
        data.get('name') or data.get('full_name') or '',
        data.get('father_name', ''),
        data.get('gender', ''),
        data.get('dob') or data.get('date_of_birth', ''),
        data.get('nationality', 'Pakistani'),
        passport,
        data.get('passport_expiry', ''),
        cnic,
        civil_id,
        mobile,
        data.get('whatsapp', ''),
        data.get('alt_mobile', ''),
        data.get('email', ''),
        data.get('emergency_name', ''),
        data.get('emergency_relation', ''),
        data.get('emergency_phone', ''),
        evacuee_link
    ])
    return cur.lastrowid


def api_charter_register(data, source_ip='unknown'):
    """
    Public-facing charter/travel interest registration.
    1) Validates required fields
    2) Resolves or creates person_master record (with evacuee linkage)
    3) Checks for duplicate charter_interest by same person+direction
    4) Inserts charter_interest row
    5) Optionally inserts family_group + family_members
    6) Optionally inserts cargo_interest
    7) Returns reference number
    """
    # Required field validation
    name = (data.get('name') or data.get('full_name') or '').strip()
    passport = _normalize_passport(data.get('passport'))
    mobile = (data.get('mobile') or '').strip()
    direction = data.get('travel_direction', 'kw_to_pk')

    if not name or not passport or not mobile:
        return {'success': False, 'error': 'Full name, passport number, and mobile number are required.'}

    if direction not in ('kw_to_pk', 'pk_to_kw', 'both'):
        direction = 'kw_to_pk'

    db = get_db()

    # Rate limiting: max 10 submissions per IP per hour
    one_hour_ago = (datetime.now() - timedelta(hours=1)).strftime('%Y-%m-%d %H:%M:%S')
    recent = db.execute(
        "SELECT COUNT(*) c FROM audit_log WHERE user = ? AND action = 'charter_register' AND created_at > ?",
        [source_ip, one_hour_ago]).fetchone()['c']
    if recent >= 10:
        db.close()
        return {'success': False, 'error': 'Too many submissions from this device. Please try again later.'}

    # Resolve identity
    person_id = find_or_create_person(db, data)

    # Check for existing active charter_interest for same person + direction
    existing = db.execute(
        "SELECT id, reference_number, status, source_channel FROM charter_interest WHERE person_id = ? AND travel_direction = ? AND cancellation_status = 'active'",
        [person_id, direction]).fetchone()

    if existing:
        existing = dict(existing)
        ci_id = existing['id']
        ref = existing['reference_number']

        # UPDATE person_master with richer data (only fill empty or update with new non-empty values)
        pm_fields = ['full_name','father_name','gender','date_of_birth','passport_expiry',
                     'cnic','civil_id','mobile','whatsapp','alt_mobile','email',
                     'emergency_name','emergency_relation','emergency_phone']
        pm_map = {'full_name': data.get('name') or data.get('full_name',''),
                  'father_name': data.get('father_name',''),
                  'gender': data.get('gender',''),
                  'date_of_birth': data.get('dob') or data.get('date_of_birth',''),
                  'passport_expiry': data.get('passport_expiry',''),
                  'cnic': _normalize_cnic(data.get('cnic','')),
                  'civil_id': (data.get('civil_id') or '').strip(),
                  'mobile': (data.get('mobile') or '').strip(),
                  'whatsapp': data.get('whatsapp',''),
                  'alt_mobile': data.get('alt_mobile',''),
                  'email': data.get('email',''),
                  'emergency_name': data.get('emergency_name',''),
                  'emergency_relation': data.get('emergency_relation',''),
                  'emergency_phone': data.get('emergency_phone','')}
        pm_updates, pm_params = [], []
        for f in pm_fields:
            new_val = pm_map.get(f, '').strip() if pm_map.get(f) else ''
            if new_val:
                # Update: overwrite with latest non-empty value
                pm_updates.append(f"{f} = ?")
                pm_params.append(new_val)
        if pm_updates:
            pm_params.append(person_id)
            db.execute(f"UPDATE person_master SET {', '.join(pm_updates)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", pm_params)

        # UPDATE charter_interest with all new detailed fields (overwrite with non-empty)
        ci_update_fields = {
            'current_area_kuwait': data.get('current_area_kuwait', ''),
            'residency_status': data.get('residency_status', ''),
            'destination_city_pk': data.get('destination_city_pk', ''),
            'preferred_airport_pk': data.get('preferred_airport_pk', ''),
            'current_city_pk': data.get('current_city_pk', ''),
            'province_pk': data.get('province_pk', ''),
            'has_valid_civil_id': data.get('has_valid_civil_id', ''),
            'has_valid_residency': data.get('has_valid_residency', ''),
            'saudi_visa_applied': data.get('saudi_visa_applied', ''),
            'saudi_visa_approved': data.get('saudi_visa_approved', ''),
            'employer_kw': data.get('employer_kw', ''),
            'destination_area_kw': data.get('destination_area_kw', ''),
            'travel_urgency': data.get('travel_urgency', ''),
            'earliest_travel_date': data.get('earliest_travel_date', ''),
            'latest_travel_date': data.get('latest_travel_date', ''),
            'travel_readiness': data.get('travel_readiness', ''),
            'traveling_alone': data.get('traveling_alone', ''),
            'group_size': data.get('group_size', ''),
            'adults_count': data.get('adults_count', ''),
            'children_count': data.get('children_count', ''),
            'infants_count': data.get('infants_count', ''),
            'must_travel_together': data.get('must_travel_together', ''),
            'interest_level': data.get('interest_level', ''),
            'can_bear_cost': data.get('can_bear_cost', ''),
            'max_affordable_fare': data.get('max_affordable_fare', ''),
            'fare_currency': data.get('fare_currency', ''),
            'deposit_ready': data.get('deposit_ready', ''),
            'max_deposit_amount': data.get('max_deposit_amount', ''),
            'preferred_payment': data.get('preferred_payment', ''),
            'employer_sponsor': data.get('employer_sponsor', ''),
            'employer_name': data.get('employer_name', ''),
            'needs_installment': data.get('needs_installment', ''),
            'flexible_date': data.get('flexible_date', ''),
            'flexible_airport': data.get('flexible_airport', ''),
            'flexible_boarding': data.get('flexible_boarding', ''),
            'flexible_charter_vs_scheduled': data.get('flexible_charter_vs_scheduled', ''),
            'flexible_baggage': data.get('flexible_baggage', ''),
            'extra_baggage': data.get('extra_baggage', ''),
            'extra_baggage_kg': data.get('extra_baggage_kg', ''),
            'is_moh_employee': data.get('is_moh_employee', ''),
            'moh_leave_end': data.get('moh_leave_end', ''),
        }
        ci_ups, ci_ps = [], []
        for f, v in ci_update_fields.items():
            sv = str(v).strip() if v else ''
            if sv:
                ci_ups.append(f"{f} = ?")
                ci_ps.append(sv)
        if ci_ups:
            # Mark as updated via web (richer data now)
            ci_ups.append("source_channel = ?")
            ci_ps.append('web_update')
            ci_ps.append(ci_id)
            db.execute(f"UPDATE charter_interest SET {', '.join(ci_ups)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", ci_ps)

        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('charter_update_via_form', ?, ?, ?)",
                   (ci_id, source_ip, json.dumps({'name': name, 'passport': passport, 'updated_fields': len(ci_ups)})))
        db.commit()
        db.close()
        return {
            'success': True,
            'updated': True,
            'reference_number': ref,
            'id': ci_id,
            'person_id': person_id,
            'message': f'Your registration {ref} has been updated with the latest information.'
        }

    # Generate reference
    ref = _generate_charter_ref(db)

    # Insert charter_interest
    ci_fields = {
        'person_id': person_id,
        'reference_number': ref,
        'travel_direction': direction,
        'current_area_kuwait': data.get('current_area_kuwait', ''),
        'residency_status': data.get('residency_status', ''),
        'destination_city_pk': data.get('destination_city_pk', ''),
        'preferred_airport_pk': data.get('preferred_airport_pk', ''),
        'current_city_pk': data.get('current_city_pk', ''),
        'province_pk': data.get('province_pk', ''),
        'has_valid_civil_id': data.get('has_valid_civil_id', ''),
        'has_valid_residency': data.get('has_valid_residency', ''),
        'saudi_visa_applied': data.get('saudi_visa_applied', ''),
        'saudi_visa_approved': data.get('saudi_visa_approved', ''),
        'employer_kw': data.get('employer_kw', ''),
        'destination_area_kw': data.get('destination_area_kw', ''),
        'travel_urgency': data.get('travel_urgency', 'general'),
        'earliest_travel_date': data.get('earliest_travel_date', ''),
        'latest_travel_date': data.get('latest_travel_date', ''),
        'travel_readiness': data.get('travel_readiness', 'flexible'),
        'traveling_alone': data.get('traveling_alone', 'yes'),
        'group_size': int(data.get('group_size', 1) or 1),
        'adults_count': int(data.get('adults_count', 1) or 1),
        'children_count': int(data.get('children_count', 0) or 0),
        'infants_count': int(data.get('infants_count', 0) or 0),
        'must_travel_together': data.get('must_travel_together', 'yes'),
        'interest_level': data.get('interest_level', 'registering_interest'),
        'can_bear_cost': data.get('can_bear_cost', ''),
        'max_affordable_fare': float(data.get('max_affordable_fare', 0) or 0),
        'fare_currency': data.get('fare_currency', 'KWD'),
        'deposit_ready': data.get('deposit_ready', ''),
        'max_deposit_amount': float(data.get('max_deposit_amount', 0) or 0),
        'preferred_payment': data.get('preferred_payment', ''),
        'employer_sponsor': data.get('employer_sponsor', ''),
        'employer_name': data.get('employer_name', ''),
        'needs_installment': data.get('needs_installment', ''),
        'flexible_date': data.get('flexible_date', 'yes'),
        'flexible_airport': data.get('flexible_airport', 'yes'),
        'flexible_boarding': data.get('flexible_boarding', 'yes'),
        'flexible_charter_vs_scheduled': data.get('flexible_charter_vs_scheduled', 'yes'),
        'flexible_baggage': data.get('flexible_baggage', 'yes'),
        'extra_baggage': data.get('extra_baggage', 'no'),
        'extra_baggage_kg': float(data.get('extra_baggage_kg', 0) or 0),
        'source_channel': data.get('source_channel', 'web'),
        'is_moh_employee': data.get('is_moh_employee', 'no'),
        'moh_leave_end': data.get('moh_leave_end', ''),
        'status': 'Submitted'
    }

    cols = list(ci_fields.keys())
    vals = [ci_fields[c] for c in cols]
    placeholders = ', '.join(['?'] * len(cols))
    cur = db.execute(f"INSERT INTO charter_interest ({', '.join(cols)}) VALUES ({placeholders})", vals)
    ci_id = cur.lastrowid

    # Family members (if group)
    if ci_fields['traveling_alone'] == 'no' and data.get('family_members'):
        fg_cur = db.execute(
            "INSERT INTO family_group (charter_interest_id, group_label, total_members) VALUES (?, ?, ?)",
            [ci_id, f"{name} family", ci_fields['group_size']])
        fg_id = fg_cur.lastrowid
        for mem in data['family_members']:
            if isinstance(mem, dict) and mem.get('full_name'):
                db.execute(
                    "INSERT INTO family_members (family_group_id, full_name, passport, gender, date_of_birth, relationship) VALUES (?,?,?,?,?,?)",
                    [fg_id, mem.get('full_name',''), _normalize_passport(mem.get('passport','')),
                     mem.get('gender',''), mem.get('date_of_birth',''), mem.get('relationship','')])

    # Cargo interest (optional)
    if data.get('has_cargo') == 'yes' and data.get('cargo_type'):
        db.execute("""
            INSERT INTO cargo_interest
                (person_id, business_name, cargo_type, estimated_volume,
                 estimated_weight_kg, origin_city, destination,
                 special_handling, special_handling_desc)
            VALUES (?,?,?,?,?,?,?,?,?)
        """, [person_id, data.get('business_name',''), data.get('cargo_type',''),
              data.get('estimated_volume',''), float(data.get('estimated_weight_kg',0) or 0),
              data.get('origin_city',''), data.get('cargo_destination',''),
              data.get('special_handling','no'), data.get('special_handling_desc','')])

    # Audit log
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('charter_register', ?, ?, ?)",
               (ci_id, source_ip, json.dumps({'name': name, 'passport': passport, 'direction': direction, 'ref': ref})))
    db.commit()
    db.close()

    return {
        'success': True,
        'reference_number': ref,
        'id': ci_id,
        'person_id': person_id
    }


def api_charter_status_lookup(ref_or_passport):
    """
    Public status lookup by reference number (TFR-XXXX) or passport.
    Returns only safe, non-admin fields.
    """
    val = (ref_or_passport or '').strip().upper()
    if not val:
        return {'success': False, 'error': 'Please enter your reference number or passport number.'}

    db = get_db()
    row = None

    if val.startswith('TFR-'):
        row = db.execute("""
            SELECT ci.reference_number, ci.status, ci.travel_direction,
                   ci.submission_timestamp, pm.full_name
            FROM charter_interest ci
            JOIN person_master pm ON pm.id = ci.person_id
            WHERE ci.reference_number = ? AND ci.cancellation_status = 'active'
        """, [val]).fetchone()
    else:
        row = db.execute("""
            SELECT ci.reference_number, ci.status, ci.travel_direction,
                   ci.submission_timestamp, pm.full_name
            FROM charter_interest ci
            JOIN person_master pm ON pm.id = ci.person_id
            WHERE UPPER(REPLACE(pm.passport,' ','')) = ? AND ci.cancellation_status = 'active'
            ORDER BY ci.created_at DESC LIMIT 1
        """, [val]).fetchone()

    db.close()

    if not row:
        return {'success': False, 'error': 'No active registration found. Please check your reference number or passport number.'}

    row = dict(row)
    return {
        'success': True,
        'reference_number': row['reference_number'],
        'name': row['full_name'],
        'status': row['status'],
        'direction': row['travel_direction'],
        'submitted': row['submission_timestamp']
    }


def api_returnee_detail(ci_id):
    db = get_db()
    row = db.execute("""
        SELECT ci.*, pm.full_name, pm.father_name, pm.passport, pm.passport_expiry,
            pm.cnic, pm.civil_id, pm.mobile, pm.whatsapp, pm.alt_mobile,
            pm.email, pm.gender, pm.date_of_birth, pm.nationality,
            pm.emergency_name, pm.emergency_relation, pm.emergency_phone,
            pm.evacuee_link_id
        FROM charter_interest ci JOIN person_master pm ON pm.id = ci.person_id
        WHERE ci.id = ?
    """, [ci_id]).fetchone()
    db.close()
    if not row: return {'error': 'Record not found'}
    return dict(row)


def api_save_returnee(data, user):
    ci_id = data.get('id')
    if not ci_id: return {'success': False, 'error': 'Record ID required'}
    db = get_db()
    rec = db.execute("SELECT person_id FROM charter_interest WHERE id = ?", [ci_id]).fetchone()
    if not rec: db.close(); return {'success': False, 'error': 'Record not found'}
    person_id = rec['person_id']
    pm_fields = ['full_name','father_name','gender','date_of_birth','passport','passport_expiry',
                 'cnic','civil_id','mobile','whatsapp','alt_mobile','email',
                 'emergency_name','emergency_relation','emergency_phone']
    pm_up, pm_p = [], []
    for f in pm_fields:
        if f in data: pm_up.append(f"{f} = ?"); pm_p.append(data[f])
    if pm_up:
        pm_p.append(person_id)
        db.execute(f"UPDATE person_master SET {', '.join(pm_up)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", pm_p)
    ci_fields = ['travel_direction','current_area_kuwait','residency_status',
                 'destination_city_pk','preferred_airport_pk','current_city_pk','province_pk',
                 'has_valid_civil_id','has_valid_residency','saudi_visa_applied','saudi_visa_approved',
                 'employer_kw','destination_area_kw','travel_urgency','earliest_travel_date',
                 'latest_travel_date','travel_readiness','traveling_alone','group_size',
                 'adults_count','children_count','infants_count','interest_level',
                 'can_bear_cost','max_affordable_fare','deposit_ready',
                 'status','verification_status','priority_category','embassy_remarks',
                 'followup_status','allocation_status','dup_flag',
                 'is_moh_employee','moh_leave_end']
    ci_up, ci_p = [], []
    for f in ci_fields:
        if f in data: ci_up.append(f"{f} = ?"); ci_p.append(data[f])
    if ci_up:
        ci_p.append(ci_id)
        db.execute(f"UPDATE charter_interest SET {', '.join(ci_up)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", ci_p)
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('returnee_update', ?, ?, ?)",
               (ci_id, user, json.dumps(data)))
    db.commit(); db.close()
    return {'success': True, 'id': ci_id}


def api_delete_returnee(ci_id, user):
    db = get_db()
    db.execute("UPDATE charter_interest SET cancellation_status = 'cancelled', updated_at = CURRENT_TIMESTAMP WHERE id = ?", [ci_id])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('returnee_delete', ?, ?, 'Cancelled')", (ci_id, user))
    db.commit(); db.close()
    return {'success': True}


def api_returnee_duplicates(ci_id):
    db = get_db()
    rec = db.execute("""
        SELECT pm.passport, pm.cnic, pm.mobile, pm.full_name
        FROM charter_interest ci JOIN person_master pm ON pm.id = ci.person_id WHERE ci.id = ?
    """, [ci_id]).fetchone()
    if not rec: db.close(); return {'duplicates': []}
    passport = (rec['passport'] or '').strip().upper()
    cnic = re.sub(r'[\s\-]', '', rec['cnic'] or '')
    mobile = (rec['mobile'] or '').strip()
    seen = set(); dupes = []
    def add_rows(rows):
        for r in rows:
            if r['ci_id'] != ci_id and r['ci_id'] not in seen:
                seen.add(r['ci_id']); dupes.append(dict(r))
    q = """SELECT ci.id as ci_id, ci.reference_number, ci.status, ci.travel_direction,
            ci.dup_flag, ci.submission_timestamp,
            pm.full_name, pm.passport, pm.cnic, pm.mobile, pm.gender
        FROM charter_interest ci JOIN person_master pm ON pm.id = ci.person_id
        WHERE {cond} AND ci.cancellation_status = 'active'"""
    if passport: add_rows(db.execute(q.format(cond="UPPER(TRIM(pm.passport)) = ?"), [passport]).fetchall())
    if cnic: add_rows(db.execute(q.format(cond="REPLACE(REPLACE(pm.cnic,'-',''),' ','') = ?"), [cnic]).fetchall())
    if mobile: add_rows(db.execute(q.format(cond="pm.mobile = ?"), [mobile]).fetchall())
    db.close()
    return {'main': dict(rec), 'duplicates': dupes}


def api_export_returnees_csv():
    db = get_db()
    rows = db.execute("""
        SELECT ci.id, ci.reference_number, ci.travel_direction, ci.status,
            ci.current_city_pk, ci.province_pk, ci.destination_area_kw,
            ci.employer_kw, ci.travel_urgency, ci.travel_readiness,
            ci.traveling_alone, ci.group_size, ci.interest_level,
            ci.saudi_visa_applied, ci.saudi_visa_approved,
            ci.is_moh_employee, ci.moh_leave_end,
            ci.verification_status, ci.dup_flag, ci.embassy_remarks,
            ci.submission_timestamp, ci.created_at,
            pm.full_name, pm.passport, pm.cnic, pm.civil_id,
            pm.mobile, pm.whatsapp, pm.email, pm.gender
        FROM charter_interest ci JOIN person_master pm ON pm.id = ci.person_id
        WHERE ci.cancellation_status = 'active' ORDER BY ci.id
    """).fetchall()
    db.close()
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(['S.No','Reference','Direction','Status','Full Name','Passport','CNIC','Civil ID',
                     'Gender','Mobile','WhatsApp','Email','Employer KW','City PK','Province','Dest Area KW',
                     'Urgency','Readiness','Interest','Visa Applied','Visa Approved',
                     'MOH Employee','Leave Ends','Dup Flag','Remarks','Submitted','Created'])
    for i, r in enumerate(rows, 1):
        writer.writerow([i, r['reference_number'], r['travel_direction'], r['status'],
                        r['full_name'], r['passport'], r['cnic'], r['civil_id'],
                        r['gender'], r['mobile'], r['whatsapp'], r['email'],
                        r['employer_kw'], r['current_city_pk'], r['province_pk'], r['destination_area_kw'],
                        r['travel_urgency'], r['travel_readiness'], r['interest_level'],
                        r['saudi_visa_applied'], r['saudi_visa_approved'],
                        r['is_moh_employee'], r['moh_leave_end'], r['dup_flag'],
                        r['embassy_remarks'], r['submission_timestamp'], r['created_at']])
    return output.getvalue()


def import_returnees_csv(csv_text, user='system'):
    """Import returnees from Google Forms CSV with auto column mapping."""
    stats = {'imported': 0, 'skipped_dup': 0, 'updated': 0, 'errors': 0, 'details': []}
    reader = csv.DictReader(io.StringIO(csv_text))
    col_map = {}
    for orig_col in (reader.fieldnames or []):
        cl = orig_col.strip().lower()
        if 'timestamp' in cl: col_map[orig_col] = 'timestamp'
        elif cl.startswith('name') or cl == 'name': col_map[orig_col] = 'name'
        elif 'passport' in cl: col_map[orig_col] = 'passport'
        elif 'gender' in cl: col_map[orig_col] = 'gender'
        elif 'country' in cl and 'resident' in cl: col_map[orig_col] = 'country'
        elif 'civil id' in cl or 'civilid' in cl or 'civil_id' in cl: col_map[orig_col] = 'civil_id'
        elif 'border' in cl: col_map[orig_col] = 'border_crossing'
        elif 'mobile' in cl or 'phone' in cl: col_map[orig_col] = 'mobile'
        elif 'profession' in cl or 'company' in cl or 'department' in cl: col_map[orig_col] = 'employer'
        elif 'email' in cl: col_map[orig_col] = 'email'
        elif 'cnic' in cl: col_map[orig_col] = 'cnic'
    db = get_db()
    row_num = 0
    for row in reader:
        row_num += 1
        try:
            rec = {}
            for orig_col, field in col_map.items():
                val = row.get(orig_col, '').strip()
                if val: rec[field] = val
            name = rec.get('name', '').strip()
            passport = (rec.get('passport', '') or '').strip().upper().replace(' ', '')
            if not name or not passport:
                stats['errors'] += 1
                stats['details'].append(f"Row {row_num}: Missing name or passport, skipped")
                continue
            cnic = re.sub(r'[\s\-]', '', rec.get('cnic', '') or '')
            civil_id = rec.get('civil_id', '').strip()
            mobile = rec.get('mobile', '').strip()
            email = rec.get('email', '').strip()
            employer = rec.get('employer', '').strip()
            gender = rec.get('gender', '').strip()
            country = rec.get('country', '').strip()
            # Auto-detect MOH employee
            is_moh = 'no'
            emp_lower = employer.lower()
            if any(kw in emp_lower for kw in ['ministry of health', 'moh', 'nurse']):
                is_moh = 'yes'
            # Check existing person_master
            existing_person = db.execute(
                "SELECT id FROM person_master WHERE UPPER(REPLACE(passport,' ','')) = ?", [passport]).fetchone()
            if existing_person:
                person_id = existing_person['id']
                existing_ci = db.execute(
                    "SELECT id, reference_number FROM charter_interest WHERE person_id = ? AND cancellation_status = 'active'",
                    [person_id]).fetchone()
                if existing_ci:
                    stats['skipped_dup'] += 1
                    stats['details'].append(f"Row {row_num}: {name} ({passport}) — already {existing_ci['reference_number']}")
                    continue
            else:
                cur = db.execute(
                    "INSERT INTO person_master (full_name, gender, passport, cnic, civil_id, mobile, email, created_at) VALUES (?,?,?,?,?,?,?, CURRENT_TIMESTAMP)",
                    [name, gender, passport, cnic, civil_id, mobile, email])
                person_id = cur.lastrowid
            # Generate ref
            while True:
                num = secrets.randbelow(9000) + 1000
                ref = f'TFR-{num}'
                if not db.execute("SELECT 1 FROM charter_interest WHERE reference_number = ?", [ref]).fetchone():
                    break
            direction = 'pk_to_kw' if country.lower() in ('pakistan', 'pk') else 'kw_to_pk'
            ts = rec.get('timestamp', datetime.now().strftime('%Y-%m-%d %H:%M:%S'))
            db.execute("""
                INSERT INTO charter_interest
                    (person_id, reference_number, travel_direction, employer_kw,
                     is_moh_employee, status, source_channel, submission_timestamp)
                VALUES (?,?,?,?,?,?,?,?)
            """, [person_id, ref, direction, employer, is_moh, 'Submitted', 'csv_import', ts])
            stats['imported'] += 1
            moh_tag = ' [MOH]' if is_moh == 'yes' else ''
            stats['details'].append(f"Row {row_num}: {name} ({passport}) — {ref}{moh_tag}")
        except Exception as e:
            stats['errors'] += 1
            stats['details'].append(f"Row {row_num}: Error — {str(e)}")
    db.commit()
    db.execute("INSERT INTO audit_log (action, user, details) VALUES (?, ?, ?)",
               ('returnee_csv_import', user, f"Imported {stats['imported']}, skipped {stats['skipped_dup']}, errors {stats['errors']}"))
    db.commit(); db.close()
    return stats


def import_visa_approvals_csv(csv_text, user='system'):
    """Import visa approval CSV (Name + Passport columns). Auto-maps columns, updates visa_status to Approved."""
    stats = {'approved': 0, 'not_found': 0, 'already_approved': 0, 'errors': 0, 'details': []}
    reader = csv.DictReader(io.StringIO(csv_text))
    col_map = {}
    for orig_col in (reader.fieldnames or []):
        cl = orig_col.strip().lower()
        if 'name' in cl and 'file' not in cl: col_map[orig_col] = 'name'
        elif 'passport' in cl: col_map[orig_col] = 'passport'
    if 'passport' not in col_map.values():
        return {'approved': 0, 'not_found': 0, 'errors': 1, 'details': ['Could not find a Passport column in CSV']}
    db = get_db()
    row_num = 0
    for row in reader:
        row_num += 1
        try:
            rec = {}
            for orig_col, field in col_map.items():
                val = row.get(orig_col, '').strip()
                if val: rec[field] = val
            passport = (rec.get('passport', '') or '').strip().upper().replace(' ', '')
            name = rec.get('name', '').strip()
            if not passport:
                stats['errors'] += 1
                stats['details'].append(f"Row {row_num}: No passport, skipped")
                continue
            existing = db.execute(
                "SELECT id, name, passport, email, visa_status, travel_status FROM evacuees WHERE UPPER(TRIM(passport)) = ?",
                [passport]).fetchone()
            if not existing:
                stats['not_found'] += 1
                stats['details'].append(f"Row {row_num}: {name} ({passport}) — NOT FOUND in system")
                continue
            if existing['visa_status'] == 'Approved':
                stats['already_approved'] += 1
                stats['details'].append(f"Row {row_num}: {existing['name']} ({passport}) — already Approved")
                continue
            # Update visa to Approved and trigger workflow
            db.execute("""UPDATE evacuees SET visa_status='Approved', updated_at=CURRENT_TIMESTAMP, updated_by=?
                WHERE id = ?""", [user, existing['id']])
            # Auto-update travel_status via workflow
            if existing['travel_status'] == 'Pending':
                db.execute("""UPDATE evacuees SET travel_status='Visa Obtained', updated_at=CURRENT_TIMESTAMP, updated_by=?
                    WHERE id = ?""", [user, existing['id']])
            db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('visa_csv_approve', ?, ?, ?)",
                       (existing['id'], user, f"Visa approved via CSV upload for {existing['name']} ({passport})"))
            _queue_visa_approved_email(dict(existing), user)
            stats['approved'] += 1
            stats['details'].append(f"Row {row_num}: {existing['name']} ({passport}) — APPROVED ✓")
        except Exception as e:
            stats['errors'] += 1
            stats['details'].append(f"Row {row_num}: Error — {str(e)}")
    db.commit()
    db.execute("INSERT INTO audit_log (action, user, details) VALUES (?, ?, ?)",
               ('visa_csv_import', user, f"Approved {stats['approved']}, not found {stats['not_found']}, already {stats['already_approved']}"))
    db.commit(); db.close()
    return stats


