# START SERVER
# ═══════════════════════════════════════════════════════════════
if __name__ == '__main__':
    init_db()
    BACKUP_DIR.mkdir(exist_ok=True)
    _startup_backup = do_backup('startup')
    print(f'[Backup] startup: {_startup_backup}', flush=True)
    _od_on = bool(ONEDRIVE_CLIENT_ID and ONEDRIVE_CLIENT_SECRET and (ONEDRIVE_REFRESH_TOKEN or _onedrive_refresh_runtime))
    print(f'[OneDrive] configured={_od_on} (secondary upload after each successful disk backup)', flush=True)
    # Start auto-backup thread
    backup_thread = threading.Thread(target=auto_backup_scheduler, daemon=True)
    backup_thread.start()
    start_email_worker()
    _iraq_backfill = run_iraq_forwarded_email_backfill_once('startup_auto')
    print(f"[IraqEmailBackfill] {_iraq_backfill}", flush=True)
    bind_port = PORT
    server = None
    max_tries = 20
    for i in range(max_tries):
        try:
            candidate = PORT + i
            server = http.server.HTTPServer(('0.0.0.0', candidate), Handler)
            bind_port = candidate
            break
        except OSError as e:
            if getattr(e, 'errno', None) == 48:
                continue
            raise
    if server is None:
        raise OSError(f"Could not bind server to ports {PORT}-{PORT + max_tries - 1}")
    print(f"""
╔══════════════════════════════════════════════════════════╗
║   CITIZEN SUPPORT FOR TRANSIT KSA SYSTEM                          ║
║   Pakistan Embassy Kuwait                               ║
║                                                         ║
║   Server running on: http://localhost:{bind_port}              ║
║                                                         ║
║   Default login:                                        ║
║     Username: admin                                     ║
║     Password: embassy2026                               ║
║                                                         ║
║   Iraq Mission CWA login:                               ║
║     Username: iraq_cwa                                  ║
║     Password: ChangeMe123!                              ║
║                                                         ║
║   Features:                                             ║
║   - Auto-backup every 2 hours (./backups/)              ║
║   - Workflow: visa approved → auto-updates status       ║
║   - Backup on every startup                             ║
║                                                         ║
║   Press Ctrl+C to stop                                  ║
╚══════════════════════════════════════════════════════════╝
""")
    if bind_port != PORT:
        print(f"[Port] {PORT} was busy; server started on {bind_port}", flush=True)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nCreating shutdown backup...")
        do_backup('shutdown')
        print("Server stopped.")
        server.server_close()
